Using default credentials is extremely dangerous and one of the most exploited vulnerabilities. In 2024, Cisco's Smart Licensing Utility (CVE-2024-20439) was compromised because of hardcoded static credentials, affecting over 50,000 enterprise devices. Attackers routinely scan for default credentials - they're the first thing checked in any attack.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const session = require('express-session');

const app = express();

app.use(express.json());
app.use(session({
  secret: 'keyboard cat',
  resave: false,
  saveUninitialized: true
}));

// DANGEROUS: Hardcoded default credentials
const ADMIN_USERNAME = 'admin';
const ADMIN_PASSWORD = 'admin123';

// Alternative danger: Credentials in config object
const defaultUsers = {
  admin: { password: 'admin', role: 'administrator' },
  user: { password: 'user123', role: 'user' }
};

app.post('/api/login', (req, res) => {
  const { username, password } = req.body;

  // Direct comparison with hardcoded credentials
  if (username === ADMIN_USERNAME && password === ADMIN_PASSWORD) {
    req.session.user = { username, role: 'admin' };
    return res.json({ success: true, message: 'Login successful' });
  }

  // Or checking against default user object
  if (defaultUsers[username] && defaultUsers[username].password === password) {
    req.session.user = { username, role: defaultUsers[username].role };
    return res.json({ success: true, message: 'Login successful' });
  }

  res.status(401).json({ success: false, message: 'Invalid credentials' });
});

app.listen(3000);
```

**Attack Payload**:
```bash
# Attackers try common default credentials
curl -X POST http://target.com/api/login \
  -H "Content-Type: application/json" \
  -d '{"username":"admin","password":"admin123"}'

# Automated scanning with default credential lists
hydra -L users.txt -P defaults.txt http-post-form \
  "/api/login:username=^USER^&password=^PASS^:Invalid"
```

**Why This Is Dangerous**:
- Default credentials are publicly known and included in attack tools like Hydra, Metasploit, and Nmap
- Hardcoded secrets in source code get committed to version control and exposed
- Attackers maintain massive databases of default credentials for all common applications
- No mechanism to force credential changes before production deployment

**SECURE VERSION**:

```javascript
const express = require('express');
const session = require('express-session');
const bcrypt = require('bcrypt');
const crypto = require('crypto');

const app = express();

app.use(express.json());
app.use(session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 3600000 // 1 hour
  }
}));

// SECURE: Credentials from environment variables only
const REQUIRED_ENV_VARS = ['ADMIN_PASSWORD_HASH', 'SESSION_SECRET'];

function validateEnvironment() {
  const missing = REQUIRED_ENV_VARS.filter(v => !process.env[v]);
  if (missing.length > 0) {
    console.error(`FATAL: Missing required environment variables: ${missing.join(', ')}`);
    console.error('Application cannot start with default credentials.');
    process.exit(1);
  }
}

validateEnvironment();

// User store should be database-backed in production
const userService = {
  async findByUsername(username) {
    // In production, query from database
    // Password hash must be generated externally and stored securely
    if (username === process.env.ADMIN_USERNAME) {
      return {
        username: process.env.ADMIN_USERNAME,
        passwordHash: process.env.ADMIN_PASSWORD_HASH,
        role: 'admin',
        mustChangePassword: process.env.FORCE_PASSWORD_CHANGE === 'true'
      };
    }
    return null;
  }
};

app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;

  if (!username || !password) {
    return res.status(400).json({ success: false, message: 'Credentials required' });
  }

  const user = await userService.findByUsername(username);

  if (!user) {
    // Constant-time comparison to prevent user enumeration
    await bcrypt.compare(password, '$2b$10$invalidhashtopreventtiming');
    return res.status(401).json({ success: false, message: 'Invalid credentials' });
  }

  const passwordValid = await bcrypt.compare(password, user.passwordHash);

  if (!passwordValid) {
    return res.status(401).json({ success: false, message: 'Invalid credentials' });
  }

  req.session.user = { username: user.username, role: user.role };

  // Force password change if using initial credentials
  if (user.mustChangePassword) {
    return res.json({ 
      success: true, 
      requirePasswordChange: true,
      message: 'Password change required'
    });
  }

  res.json({ success: true, message: 'Login successful' });
});

app.listen(3000);
```

**Key Security Controls**:
- **Environment-based secrets**: Credentials are never hardcoded; they come from environment variables that must be set
- **Startup validation**: Application fails to start if required secrets are missing, preventing accidental deployment with defaults
- **Password hashing**: Uses bcrypt for secure password storage and comparison
- **Forced password change**: Flag to require password update on first login if initial credentials were set by admin

Excellent question! The initial setup phase is critical because it's when systems are most vulnerable. The secure approach is a one-time setup token or first-run initialization that creates credentials dynamically and expires immediately after use.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const session = require('express-session');
const bcrypt = require('bcrypt');
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const app = express();

app.use(express.json());
app.use(session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: { secure: true, httpOnly: true, sameSite: 'strict' }
}));

// Database simulation (use real DB in production)
const db = {
  users: new Map(),
  setupToken: null,
  setupComplete: false
};

class SecureSetupManager {
  constructor() {
    this.setupTokenPath = path.join(process.cwd(), '.setup-token');
    this.setupCompletePath = path.join(process.cwd(), '.setup-complete');
    this.tokenExpiryMs = 30 * 60 * 1000; // 30 minutes
  }

  isSetupComplete() {
    return fs.existsSync(this.setupCompletePath) || db.setupComplete;
  }

  generateSetupToken() {
    if (this.isSetupComplete()) {
      throw new Error('Setup already completed');
    }

    const token = crypto.randomBytes(32).toString('hex');
    const expiry = Date.now() + this.tokenExpiryMs;

    const tokenData = {
      token: crypto.createHash('sha256').update(token).digest('hex'),
      expiry,
      used: false
    };

    db.setupToken = tokenData;

    // Log token to console and secure file (for admin to retrieve)
    console.log('\n========================================');
    console.log('INITIAL SETUP TOKEN (expires in 30 minutes)');
    console.log(`Token: ${token}`);
    console.log(`Setup URL: https://yourserver.com/setup?token=${token}`);
    console.log('========================================\n');

    // Also write to a secure file readable only by root/admin
    fs.writeFileSync(this.setupTokenPath, token, { mode: 0o600 });

    return token;
  }

  validateSetupToken(providedToken) {
    if (this.isSetupComplete()) {
      return { valid: false, error: 'Setup already completed' };
    }

    if (!db.setupToken) {
      return { valid: false, error: 'No setup token generated' };
    }

    if (db.setupToken.used) {
      return { valid: false, error: 'Token already used' };
    }

    if (Date.now() > db.setupToken.expiry) {
      this.invalidateToken();
      return { valid: false, error: 'Token expired' };
    }

    const providedHash = crypto.createHash('sha256').update(providedToken).digest('hex');
    const tokenValid = crypto.timingSafeEqual(
      Buffer.from(providedHash),
      Buffer.from(db.setupToken.token)
    );

    if (!tokenValid) {
      return { valid: false, error: 'Invalid token' };
    }

    return { valid: true };
  }

  async completeSetup(token, adminCredentials) {
    const validation = this.validateSetupToken(token);
    if (!validation.valid) {
      throw new Error(validation.error);
    }

    // Validate password strength
    const passwordIssues = this.validatePasswordStrength(adminCredentials.password);
    if (passwordIssues.length > 0) {
      throw new Error(`Password requirements not met: ${passwordIssues.join(', ')}`);
    }

    // Create admin user with secure password hash
    const saltRounds = 12;
    const passwordHash = await bcrypt.hash(adminCredentials.password, saltRounds);

    db.users.set(adminCredentials.username, {
      username: adminCredentials.username,
      passwordHash,
      role: 'admin',
      createdAt: new Date().toISOString(),
      mustChangePassword: false,
      loginAttempts: 0
    });

    // Mark setup complete
    db.setupToken.used = true;
    db.setupComplete = true;
    fs.writeFileSync(this.setupCompletePath, new Date().toISOString(), { mode: 0o600 });

    // Securely delete setup token file
    if (fs.existsSync(this.setupTokenPath)) {
      fs.unlinkSync(this.setupTokenPath);
    }

    console.log(`[AUDIT] Initial admin account created: ${adminCredentials.username} at ${new Date().toISOString()}`);

    return { success: true };
  }

  validatePasswordStrength(password) {
    const issues = [];
    if (password.length < 12) issues.push('minimum 12 characters');
    if (!/[A-Z]/.test(password)) issues.push('uppercase letter required');
    if (!/[a-z]/.test(password)) issues.push('lowercase letter required');
    if (!/[0-9]/.test(password)) issues.push('number required');
    if (!/[^A-Za-z0-9]/.test(password)) issues.push('special character required');

    // Check against common passwords
    const commonPasswords = ['password123', 'admin123', 'letmein', 'welcome1'];
    if (commonPasswords.includes(password.toLowerCase())) {
      issues.push('password too common');
    }

    return issues;
  }

  invalidateToken() {
    db.setupToken = null;
    if (fs.existsSync(this.setupTokenPath)) {
      fs.unlinkSync(this.setupTokenPath);
    }
  }
}

const setupManager = new SecureSetupManager();

// Setup routes - only available before setup completion
app.get('/api/setup/status', (req, res) => {
  res.json({ setupComplete: setupManager.isSetupComplete() });
});

app.post('/api/setup/init', (req, res) => {
  // Only allow from localhost during initial setup
  const allowedIPs = ['127.0.0.1', '::1', '::ffff:127.0.0.1'];
  if (!allowedIPs.includes(req.ip)) {
    console.log(`[SECURITY] Setup init attempt from unauthorized IP: ${req.ip}`);
    return res.status(403).json({ error: 'Setup must be initiated locally' });
  }

  try {
    setupManager.generateSetupToken();
    res.json({ success: true, message: 'Setup token generated. Check server logs or .setup-token file.' });
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

app.post('/api/setup/complete', async (req, res) => {
  const { token, username, password } = req.body;

  if (!token || !username || !password) {
    return res.status(400).json({ error: 'Token, username, and password required' });
  }

  try {
    await setupManager.completeSetup(token, { username, password });
    res.json({ success: true, message: 'Admin account created successfully' });
  } catch (error) {
    console.log(`[SECURITY] Setup completion failed: ${error.message}`);
    res.status(400).json({ error: error.message });
  }
});

// Middleware to block all routes until setup is complete
app.use((req, res, next) => {
  if (req.path.startsWith('/api/setup')) {
    return next();
  }

  if (!setupManager.isSetupComplete()) {
    return res.status(503).json({ error: 'System setup required' });
  }

  next();
});

// Startup check
if (!setupManager.isSetupComplete()) {
  console.log('\n[NOTICE] Initial setup required.');
  console.log('Run: curl -X POST http://localhost:3000/api/setup/init');
  console.log('Then complete setup with the generated token.\n');
}

app.listen(3000, () => {
  console.log('Server running on port 3000');
});
```

**Defense in Depth Layers**:

1. **One-Time Setup Token**: Token is cryptographically random, hashed for storage, and expires after 30 minutes
```javascript
const token = crypto.randomBytes(32).toString('hex');
const hashedToken = crypto.createHash('sha256').update(token).digest('hex');
```

2. **Localhost-Only Initialization**: Setup token generation only allowed from local machine
```javascript
const allowedIPs = ['127.0.0.1', '::1', '::ffff:127.0.0.1'];
if (!allowedIPs.includes(req.ip)) {
  return res.status(403).json({ error: 'Setup must be initiated locally' });
}
```

3. **Password Strength Enforcement**: Strong password requirements enforced at creation
```javascript
if (password.length < 12) issues.push('minimum 12 characters');
if (!/[A-Z]/.test(password)) issues.push('uppercase letter required');
```

**Additional Protections**:
- **Token invalidation**: Setup token is immediately invalidated after use or expiry
- **Setup completion lock**: Once setup is complete, all setup endpoints are permanently disabled
- **Audit logging**: All setup activities are logged with timestamps and IP addresses
- **Secure file permissions**: Token files use mode 0o600 (owner read/write only)
- **Timing-safe comparison**: Uses crypto.timingSafeEqual to prevent timing attacks on token validation
- **Service unavailable until setup**: Application returns 503 for all routes until initial setup is complete, preventing use with no authentication configured

Hardcoding credentials directly in source code is one of the most dangerous security mistakes. In July 2024, Cisco disclosed CVE-2024-20419 where hardcoded credentials in Smart Software Manager On-Prem received a perfect CVSS score of 10.0, allowing complete system takeover.

**VULNERABLE CODE**:

```java
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;

public class DatabaseService {
    // DANGEROUS: Hardcoded credentials in source code
    private static final String DB_URL = "jdbc:postgresql://prod-db.internal:5432/customers";
    private static final String DB_USER = "admin";
    private static final String DB_PASSWORD = "SuperSecret123!";

    // Also dangerous: API keys and tokens
    private static final String API_KEY = "sk-live-abc123xyz789";
    private static final String JWT_SECRET = "my-super-secret-jwt-key-2024";

    public Connection getConnection() throws SQLException {
        return DriverManager.getConnection(DB_URL, DB_USER, DB_PASSWORD);
    }

    public User authenticateUser(String username, String password) throws SQLException {
        // Backdoor account - extremely dangerous
        if (username.equals("backdoor") && password.equals("maintenance123")) {
            return new User("admin", "ADMIN");
        }

        try (Connection conn = getConnection()) {
            PreparedStatement stmt = conn.prepareStatement(
                "SELECT * FROM users WHERE username = ? AND password = ?"
            );
            stmt.setString(1, username);
            stmt.setString(2, password);
            ResultSet rs = stmt.executeQuery();
            if (rs.next()) {
                return new User(rs.getString("username"), rs.getString("role"));
            }
        }
        return null;
    }
}
```

**Attack Vectors**:
```bash
# Decompile JAR file to extract credentials
jd-gui application.jar
# or
jadx -d output/ application.jar

# Search for hardcoded strings
strings application.jar | grep -i password
strings application.jar | grep -i secret

# Binary analysis with grep
grep -r "jdbc:" ./classes/
grep -r "password" ./classes/
```

**Why This Is Dangerous**:
- Credentials are compiled into bytecode and easily extracted with decompilers (JD-GUI, JADX, CFR)
- Version control history permanently stores credentials even if removed later
- All developers and anyone with repository access can see production credentials
- Backdoor accounts allow attackers to bypass normal authentication entirely
- Cannot rotate credentials without recompiling and redeploying application

**SECURE VERSION**:

```java
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.logging.Logger;

public class SecureDatabaseService {
    private static final Logger logger = Logger.getLogger(SecureDatabaseService.class.getName());

    // Credentials loaded from environment variables
    private final String dbUrl;
    private final String dbUser;
    private final String dbPassword;

    public SecureDatabaseService() {
        // Load from environment variables (set by deployment platform)
        this.dbUrl = getRequiredEnvVar("DATABASE_URL");
        this.dbUser = getRequiredEnvVar("DATABASE_USER");
        this.dbPassword = getRequiredEnvVar("DATABASE_PASSWORD");
    }

    private String getRequiredEnvVar(String name) {
        String value = System.getenv(name);
        if (value == null || value.trim().isEmpty()) {
            logger.severe("Required environment variable not set: " + name);
            throw new IllegalStateException(
                "Missing required configuration. Contact system administrator."
            );
        }
        return value;
    }

    public Connection getConnection() throws SQLException {
        return DriverManager.getConnection(dbUrl, dbUser, dbPassword);
    }

    public User authenticateUser(String username, String password) throws SQLException {
        // No backdoor accounts - all authentication through database
        if (username == null || password == null) {
            logger.warning("Authentication attempt with null credentials");
            return null;
        }

        try (Connection conn = getConnection()) {
            PreparedStatement stmt = conn.prepareStatement(
                "SELECT username, role, password_hash FROM users WHERE username = ?"
            );
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                String storedHash = rs.getString("password_hash");
                // Use bcrypt or Argon2 for password verification
                if (PasswordHasher.verify(password, storedHash)) {
                    logger.info("Successful authentication for user: " + username);
                    return new User(rs.getString("username"), rs.getString("role"));
                }
            }
            logger.warning("Failed authentication attempt for user: " + username);
        }
        return null;
    }
}
```

**Key Security Controls**:
- **Environment variables**: Credentials never appear in source code or compiled artifacts
- **Fail-fast validation**: Application won't start without required configuration
- **No backdoor accounts**: All authentication goes through the same secure path
- **Password hashing**: Passwords stored as hashes, not plaintext
- **Audit logging**: All authentication attempts are logged for monitoring

For enterprise environments, you need a dedicated secrets management solution like HashiCorp Vault, AWS Secrets Manager, or Azure Key Vault. These provide automatic rotation, access auditing, fine-grained permissions, and centralized management.

**PRODUCTION PATTERN WITH HASHICORP VAULT**:

```java
import com.bettercloud.vault.Vault;
import com.bettercloud.vault.VaultConfig;
import com.bettercloud.vault.VaultException;
import com.bettercloud.vault.response.LogicalResponse;
import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;

import javax.sql.DataSource;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.time.Instant;
import java.util.Map;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicReference;
import java.util.logging.Level;
import java.util.logging.Logger;

public class EnterpriseSecureDatabaseService implements AutoCloseable {
    private static final Logger logger = Logger.getLogger(EnterpriseSecureDatabaseService.class.getName());

    private final Vault vault;
    private final AtomicReference<HikariDataSource> dataSourceRef;
    private final ScheduledExecutorService scheduler;
    private final String secretPath;
    private final AuditLogger auditLogger;

    public EnterpriseSecureDatabaseService(AuditLogger auditLogger) throws VaultException {
        this.auditLogger = auditLogger;

        // Vault authentication using Kubernetes service account or AppRole
        VaultConfig config = new VaultConfig()
            .address(System.getenv("VAULT_ADDR"))
            .token(getVaultToken())
            .engineVersion(2)
            .build();

        this.vault = new Vault(config);
        this.secretPath = System.getenv().getOrDefault("VAULT_SECRET_PATH", "secret/data/myapp/database");
        this.dataSourceRef = new AtomicReference<>();

        // Initial credential fetch
        refreshCredentials();

        // Schedule automatic credential rotation check every 5 minutes
        this.scheduler = Executors.newSingleThreadScheduledExecutor();
        scheduler.scheduleAtFixedRate(this::refreshCredentialsIfNeeded, 5, 5, TimeUnit.MINUTES);

        logger.info("EnterpriseSecureDatabaseService initialized with Vault integration");
    }

    private String getVaultToken() {
        // Try Kubernetes service account token first
        String k8sToken = System.getenv("VAULT_K8S_TOKEN");
        if (k8sToken != null && !k8sToken.isEmpty()) {
            // Exchange K8s token for Vault token via Kubernetes auth method
            return authenticateWithKubernetes(k8sToken);
        }

        // Fall back to AppRole authentication
        String roleId = System.getenv("VAULT_ROLE_ID");
        String secretId = System.getenv("VAULT_SECRET_ID");
        if (roleId != null && secretId != null) {
            return authenticateWithAppRole(roleId, secretId);
        }

        throw new IllegalStateException("No valid Vault authentication method configured");
    }

    private String authenticateWithKubernetes(String jwt) {
        // Implementation would use Vault Kubernetes auth
        // Returns a short-lived Vault token
        return "s.kubernetes-token";
    }

    private String authenticateWithAppRole(String roleId, String secretId) {
        // Implementation would use Vault AppRole auth
        return "s.approle-token";
    }

    private void refreshCredentials() {
        try {
            LogicalResponse response = vault.logical().read(secretPath);
            Map<String, String> secrets = response.getData();

            String dbUrl = secrets.get("url");
            String dbUser = secrets.get("username");
            String dbPassword = secrets.get("password");

            if (dbUrl == null || dbUser == null || dbPassword == null) {
                throw new VaultException("Incomplete database credentials in Vault");
            }

            // Create new connection pool with fresh credentials
            HikariConfig hikariConfig = new HikariConfig();
            hikariConfig.setJdbcUrl(dbUrl);
            hikariConfig.setUsername(dbUser);
            hikariConfig.setPassword(dbPassword);
            hikariConfig.setMaximumPoolSize(10);
            hikariConfig.setMinimumIdle(2);
            hikariConfig.setConnectionTimeout(30000);
            hikariConfig.setIdleTimeout(600000);
            hikariConfig.setMaxLifetime(1800000);
            hikariConfig.setLeakDetectionThreshold(60000);

            HikariDataSource newDataSource = new HikariDataSource(hikariConfig);
            HikariDataSource oldDataSource = dataSourceRef.getAndSet(newDataSource);

            // Gracefully close old connection pool
            if (oldDataSource != null) {
                scheduler.schedule(() -> oldDataSource.close(), 30, TimeUnit.SECONDS);
            }

            auditLogger.logEvent("CREDENTIALS_ROTATED", "Database credentials refreshed from Vault");
            logger.info("Database credentials successfully refreshed");

        } catch (VaultException e) {
            logger.log(Level.SEVERE, "Failed to fetch credentials from Vault", e);
            auditLogger.logEvent("CREDENTIALS_FETCH_FAILED", "Vault error: " + e.getMessage());
            throw new RuntimeException("Unable to fetch database credentials", e);
        }
    }

    private void refreshCredentialsIfNeeded() {
        try {
            // Check if credentials are about to expire based on Vault lease
            // In production, track lease duration and renew before expiry
            refreshCredentials();
        } catch (Exception e) {
            logger.log(Level.WARNING, "Scheduled credential refresh failed", e);
        }
    }

    public Connection getConnection() throws SQLException {
        HikariDataSource dataSource = dataSourceRef.get();
        if (dataSource == null) {
            throw new SQLException("Database service not initialized");
        }
        return dataSource.getConnection();
    }

    public AuthenticationResult authenticateUser(String username, String password, String clientIp) {
        Instant startTime = Instant.now();

        // Input validation
        if (username == null || username.length() < 3 || username.length() > 64) {
            auditLogger.logAuthAttempt(username, clientIp, "INVALID_USERNAME", startTime);
            return AuthenticationResult.failure("Invalid credentials");
        }

        if (password == null || password.length() < 8) {
            auditLogger.logAuthAttempt(username, clientIp, "INVALID_PASSWORD_FORMAT", startTime);
            return AuthenticationResult.failure("Invalid credentials");
        }

        try (Connection conn = getConnection()) {
            PreparedStatement stmt = conn.prepareStatement(
                "SELECT id, username, role, password_hash, account_locked, failed_attempts, " +
                "last_failed_attempt FROM users WHERE username = ? AND active = true"
            );
            stmt.setString(1, username.toLowerCase());
            ResultSet rs = stmt.executeQuery();

            if (!rs.next()) {
                // Perform dummy hash comparison to prevent timing attacks
                PasswordHasher.verify(password, PasswordHasher.getDummyHash());
                auditLogger.logAuthAttempt(username, clientIp, "USER_NOT_FOUND", startTime);
                return AuthenticationResult.failure("Invalid credentials");
            }

            // Check account lockout
            boolean accountLocked = rs.getBoolean("account_locked");
            int failedAttempts = rs.getInt("failed_attempts");

            if (accountLocked) {
                auditLogger.logAuthAttempt(username, clientIp, "ACCOUNT_LOCKED", startTime);
                return AuthenticationResult.failure("Account is locked. Contact support.");
            }

            String storedHash = rs.getString("password_hash");
            if (PasswordHasher.verify(password, storedHash)) {
                // Successful authentication
                resetFailedAttempts(conn, rs.getLong("id"));
                auditLogger.logAuthAttempt(username, clientIp, "SUCCESS", startTime);

                return AuthenticationResult.success(
                    new User(rs.getLong("id"), rs.getString("username"), rs.getString("role"))
                );
            } else {
                // Failed authentication
                int newFailedAttempts = incrementFailedAttempts(conn, rs.getLong("id"), failedAttempts);
                auditLogger.logAuthAttempt(username, clientIp, "WRONG_PASSWORD", startTime);

                if (newFailedAttempts >= 5) {
                    lockAccount(conn, rs.getLong("id"));
                    auditLogger.logEvent("ACCOUNT_LOCKED", "Account locked due to failed attempts: " + username);
                }

                return AuthenticationResult.failure("Invalid credentials");
            }

        } catch (SQLException e) {
            logger.log(Level.SEVERE, "Database error during authentication", e);
            auditLogger.logAuthAttempt(username, clientIp, "DATABASE_ERROR", startTime);
            return AuthenticationResult.failure("Authentication service unavailable");
        }
    }

    private void resetFailedAttempts(Connection conn, long userId) throws SQLException {
        PreparedStatement stmt = conn.prepareStatement(
            "UPDATE users SET failed_attempts = 0, last_failed_attempt = NULL WHERE id = ?"
        );
        stmt.setLong(1, userId);
        stmt.executeUpdate();
    }

    private int incrementFailedAttempts(Connection conn, long userId, int current) throws SQLException {
        int newCount = current + 1;
        PreparedStatement stmt = conn.prepareStatement(
            "UPDATE users SET failed_attempts = ?, last_failed_attempt = NOW() WHERE id = ?"
        );
        stmt.setInt(1, newCount);
        stmt.setLong(2, userId);
        stmt.executeUpdate();
        return newCount;
    }

    private void lockAccount(Connection conn, long userId) throws SQLException {
        PreparedStatement stmt = conn.prepareStatement(
            "UPDATE users SET account_locked = true WHERE id = ?"
        );
        stmt.setLong(1, userId);
        stmt.executeUpdate();
    }

    @Override
    public void close() {
        scheduler.shutdown();
        HikariDataSource dataSource = dataSourceRef.get();
        if (dataSource != null) {
            dataSource.close();
        }
    }
}
