Service account credentials require a different approach than user passwords. The 2023 CircleCI breach demonstrated this when hardcoded secrets in CI/CD pipelines exposed customer secrets. For machine-to-machine authentication, you need automated rotation, secure storage, and proper scoping.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"crypto/sha256"
	"database/sql"
	"encoding/hex"
	"fmt"
	"log"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/service/secretsmanager"
	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

// ServiceCredential represents a service account with rotation support
type ServiceCredential struct {
	ID              string
	ServiceName     string
	APIKeyHash      string
	Scopes          []string
	CreatedAt       time.Time
	ExpiresAt       time.Time
	RotatedAt       *time.Time
	IsActive        bool
	PreviousKeyHash string // Support dual-key during rotation
}

type CredentialManager struct {
	db            *sql.DB
	secretsClient *secretsmanager.Client
	keyCache      map[string]*ServiceCredential
	cacheMutex    sync.RWMutex
	auditLogger   *log.Logger
}

// NewCredentialManager initializes the credential management system
func NewCredentialManager(db *sql.DB) (*CredentialManager, error) {
	// Load AWS config for Secrets Manager
	cfg, err := config.LoadDefaultConfig(context.Background())
	if err != nil {
		return nil, fmt.Errorf("failed to load AWS config: %w", err)
	}

	auditFile, err := os.OpenFile("/var/log/credentials-audit.log",
		os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0600)
	if err != nil {
		return nil, fmt.Errorf("failed to open audit log: %w", err)
	}

	return &CredentialManager{
		db:            db,
		secretsClient: secretsmanager.NewFromConfig(cfg),
		keyCache:      make(map[string]*ServiceCredential),
		auditLogger:   log.New(auditFile, "", log.LstdFlags),
	}, nil
}

// GenerateAPIKey creates a cryptographically secure API key
func GenerateAPIKey() (string, error) {
	bytes := make([]byte, 32)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	// Format: svc_<hex_encoded_random_bytes>
	return fmt.Sprintf("svc_%s", hex.EncodeToString(bytes)), nil
}

// HashAPIKey creates a secure hash for storage
func HashAPIKey(apiKey string) string {
	hash := sha256.Sum256([]byte(apiKey))
	return hex.EncodeToString(hash[:])
}

// CreateServiceCredential generates a new service account with scoped permissions
func (cm *CredentialManager) CreateServiceCredential(ctx context.Context,
	serviceName string, scopes []string, ttlDays int) (string, error) {

	// Validate service name format
	if !isValidServiceName(serviceName) {
		return "", fmt.Errorf("invalid service name format")
	}

	// Validate scopes against allowed list
	if err := validateScopes(scopes); err != nil {
		return "", fmt.Errorf("invalid scopes: %w", err)
	}

	// Generate secure API key
	apiKey, err := GenerateAPIKey()
	if err != nil {
		return "", fmt.Errorf("failed to generate API key: %w", err)
	}

	apiKeyHash := HashAPIKey(apiKey)
	expiresAt := time.Now().AddDate(0, 0, ttlDays)

	// Store hashed key in database
	_, err = cm.db.ExecContext(ctx, `
		INSERT INTO service_credentials 
		(service_name, api_key_hash, scopes, expires_at, is_active)
		VALUES ($1, $2, $3, $4, true)`,
		serviceName, apiKeyHash, strings.Join(scopes, ","), expiresAt)
	if err != nil {
		return "", fmt.Errorf("failed to store credential: %w", err)
	}

	// Store actual key in AWS Secrets Manager (not in DB)
	_, err = cm.secretsClient.CreateSecret(ctx, &secretsmanager.CreateSecretInput{
		Name:         &serviceName,
		SecretString: &apiKey,
	})
	if err != nil {
		return "", fmt.Errorf("failed to store in secrets manager: %w", err)
	}

	cm.auditLogger.Printf("[CREATE] Service credential created: service=%s scopes=%v expires=%v",
		serviceName, scopes, expiresAt)

	return apiKey, nil
}

// RotateCredential performs zero-downtime key rotation
func (cm *CredentialManager) RotateCredential(ctx context.Context, serviceName string) (string, error) {
	tx, err := cm.db.BeginTx(ctx, nil)
	if err != nil {
		return "", fmt.Errorf("failed to begin transaction: %w", err)
	}
	defer tx.Rollback()

	// Get current credential
	var currentHash string
	var scopes string
	err = tx.QueryRowContext(ctx, `
		SELECT api_key_hash, scopes FROM service_credentials 
		WHERE service_name = $1 AND is_active = true
		FOR UPDATE`, serviceName).Scan(&currentHash, &scopes)
	if err != nil {
		return "", fmt.Errorf("credential not found: %w", err)
	}

	// Generate new key
	newAPIKey, err := GenerateAPIKey()
	if err != nil {
		return "", err
	}
	newKeyHash := HashAPIKey(newAPIKey)

	// Update with new key, keep previous for grace period
	_, err = tx.ExecContext(ctx, `
		UPDATE service_credentials 
		SET api_key_hash = $1, 
		    previous_key_hash = $2,
		    rotated_at = NOW(),
		    expires_at = NOW() + INTERVAL '90 days'
		WHERE service_name = $3`,
		newKeyHash, currentHash, serviceName)
	if err != nil {
		return "", fmt.Errorf("failed to rotate: %w", err)
	}

	if err := tx.Commit(); err != nil {
		return "", fmt.Errorf("failed to commit: %w", err)
	}

	// Update Secrets Manager
	_, err = cm.secretsClient.UpdateSecret(ctx, &secretsmanager.UpdateSecretInput{
		SecretId:     &serviceName,
		SecretString: &newAPIKey,
	})
	if err != nil {
		return "", fmt.Errorf("failed to update secrets manager: %w", err)
	}

	// Invalidate cache
	cm.cacheMutex.Lock()
	delete(cm.keyCache, serviceName)
	cm.cacheMutex.Unlock()

	cm.auditLogger.Printf("[ROTATE] Credential rotated: service=%s", serviceName)

	return newAPIKey, nil
}

// ValidateAPIKey authenticates a service request with dual-key support
func (cm *CredentialManager) ValidateAPIKey(ctx context.Context,
	apiKey string, requiredScope string) (*ServiceCredential, error) {

	// Rate limiting check (would use Redis in production)
	// Omitted for brevity

	keyHash := HashAPIKey(apiKey)

	// Check cache first
	cm.cacheMutex.RLock()
	for _, cred := range cm.keyCache {
		if cred.APIKeyHash == keyHash || cred.PreviousKeyHash == keyHash {
			if time.Now().Before(cred.ExpiresAt) && cred.IsActive {
				if hasScope(cred.Scopes, requiredScope) {
					cm.cacheMutex.RUnlock()
					return cred, nil
				}
			}
		}
	}
	cm.cacheMutex.RUnlock()

	// Query database - supports both current and previous key during rotation
	var cred ServiceCredential
	var scopesStr string
	err := cm.db.QueryRowContext(ctx, `
		SELECT id, service_name, api_key_hash, previous_key_hash, scopes, 
		       created_at, expires_at, is_active
		FROM service_credentials
		WHERE (api_key_hash = $1 OR previous_key_hash = $1)
		  AND is_active = true
		  AND expires_at > NOW()`, keyHash).Scan(
		&cred.ID, &cred.ServiceName, &cred.APIKeyHash, &cred.PreviousKeyHash,
		&scopesStr, &cred.CreatedAt, &cred.ExpiresAt, &cred.IsActive)

	if err == sql.ErrNoRows {
		cm.auditLogger.Printf("[AUTH_FAIL] Invalid API key attempt: hash_prefix=%s",
			keyHash[:8])
		return nil, fmt.Errorf("invalid or expired API key")
	}
	if err != nil {
		return nil, fmt.Errorf("database error: %w", err)
	}

	cred.Scopes = strings.Split(scopesStr, ",")

	// Validate scope
	if !hasScope(cred.Scopes, requiredScope) {
		cm.auditLogger.Printf("[AUTH_FAIL] Scope violation: service=%s required=%s has=%v",
			cred.ServiceName, requiredScope, cred.Scopes)
		return nil, fmt.Errorf("insufficient permissions")
	}

	// Warn if using old key during rotation grace period
	if cred.PreviousKeyHash == keyHash {
		cm.auditLogger.Printf("[WARN] Service using pre-rotation key: service=%s",
			cred.ServiceName)
	}

	// Update cache
	cm.cacheMutex.Lock()
	cm.keyCache[cred.ServiceName] = &cred
	cm.cacheMutex.Unlock()

	return &cred, nil
}

// APIKeyMiddleware validates service credentials on requests
func (cm *CredentialManager) APIKeyMiddleware(requiredScope string) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			apiKey := r.Header.Get("X-API-Key")
			if apiKey == "" {
				apiKey = r.URL.Query().Get("api_key")
			}

			if apiKey == "" {
				http.Error(w, "API key required", http.StatusUnauthorized)
				return
			}

			cred, err := cm.ValidateAPIKey(r.Context(), apiKey, requiredScope)
			if err != nil {
				http.Error(w, "Invalid credentials", http.StatusUnauthorized)
				return
			}

			// Add service identity to context
			ctx := context.WithValue(r.Context(), "service_credential", cred)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// Helper functions
func isValidServiceName(name string) bool {
	if len(name) < 3 || len(name) > 64 {
		return false
	}
	for _, c := range name {
		if !((c >= 'a' && c <= 'z') || (c >= '0' && c <= '9') || c == '-' || c == '_') {
			return false
		}
	}
	return true
}

var allowedScopes = map[string]bool{
	"read:users": true, "write:users": true,
	"read:data": true, "write:data": true,
	"admin": true,
}

func validateScopes(scopes []string) error {
	for _, s := range scopes {
		if !allowedScopes[s] {
			return fmt.Errorf("unknown scope: %s", s)
		}
	}
	return nil
}

func hasScope(scopes []string, required string) bool {
	for _, s := range scopes {
		if s == required || s == "admin" {
			return true
		}
	}
	return false
}

func main() {
	db, _ := sql.Open("postgres", os.Getenv("DATABASE_URL"))
	cm, _ := NewCredentialManager(db)

	mux := http.NewServeMux()

	// Protected endpoint requiring read:data scope
	mux.Handle("/api/data", cm.APIKeyMiddleware("read:data")(http.HandlerFunc(
		func(w http.ResponseWriter, r *http.Request) {
			w.Write([]byte("Authenticated data access"))
		})))

	http.ListenAndServe(":8080", mux)
}
