<?php
// src/Middleware/SecretLeakagePreventionMiddleware.php

class SecretLeakagePreventionMiddleware {
    private const SECRET_PATTERNS = [
        '/sk-[a-zA-Z0-9]{24,}/',           // OpenAI keys
        '/AKIA[0-9A-Z]{16}/',               // AWS Access Keys
        '/ghp_[a-zA-Z0-9]{36}/',            // GitHub tokens
        '/xox[baprs]-[a-zA-Z0-9-]+/',       // Slack tokens
    ];

    public function process(Request $request, Handler $handler): Response {
        $response = $handler->handle($request);

        // Only check in non-production or enable sampling in prod
        if ($this->shouldCheck()) {
            $content = $response->getBody()->getContents();

            foreach (self::SECRET_PATTERNS as $pattern) {
                if (preg_match($pattern, $content)) {
                    $this->logger->critical('Potential secret leak detected in response', [
                        'uri' => $request->getUri()->getPath(),
                        'pattern' => $pattern
                    ]);

                    // In production, optionally block the response
                    if (getenv('BLOCK_SECRET_LEAKS') === 'true') {
                        return new JsonResponse(
                            ['error' => 'Internal server error'],
                            500
                        );
                    }
                }
            }
        }

        return $response;
    }
}
