**SECURE VERSION**:

```csharp
using Microsoft.AspNetCore.Identity;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using System.Security.Claims;
using Microsoft.IdentityModel.Tokens;
using System.IdentityModel.Tokens.Jwt;
using System.Text;

namespace AdminPanel.Controllers
{
    public class SecureAuthController : ControllerBase
    {
        private readonly UserManager<ApplicationUser> _userManager;
        private readonly SignInManager<ApplicationUser> _signInManager;
        private readonly IConfiguration _configuration;
        private readonly ILogger<SecureAuthController> _logger;

        public SecureAuthController(
            UserManager<ApplicationUser> userManager,
            SignInManager<ApplicationUser> signInManager,
            IConfiguration configuration,
            ILogger<SecureAuthController> logger)
        {
            _userManager = userManager;
            _signInManager = signInManager;
            _configuration = configuration;
            _logger = logger;
        }

        [HttpPost("api/login")]
        public async Task<IActionResult> Login([FromBody] LoginRequest request)
        {
            // SECURE: Credentials stored in database with proper hashing
            var user = await _userManager.FindByNameAsync(request.Username);

            if (user == null)
            {
                _logger.LogWarning("Login attempt for non-existent user: {Username}", request.Username);
                // Constant-time response to prevent user enumeration
                await Task.Delay(100);
                return Unauthorized("Invalid credentials");
            }

            // Check if account requires password change (first login detection)
            if (user.RequiresPasswordChange)
            {
                return BadRequest(new { RequiresPasswordChange = true });
            }

            var result = await _signInManager.CheckPasswordSignInAsync(
                user, request.Password, lockoutOnFailure: true);

            if (result.Succeeded)
            {
                _logger.LogInformation("User {Username} logged in successfully", user.UserName);
                var token = GenerateJwtToken(user);
                return Ok(new { Token = token });
            }

            if (result.IsLockedOut)
            {
                _logger.LogWarning("User {Username} locked out", user.UserName);
                return Unauthorized("Account locked. Please try again later.");
            }

            _logger.LogWarning("Failed login for user: {Username}", request.Username);
            return Unauthorized("Invalid credentials");
        }

        private string GenerateJwtToken(ApplicationUser user)
        {
            // SECURE: JWT secret from environment/secrets manager, not hardcoded
            var key = new SymmetricSecurityKey(
                Encoding.UTF8.GetBytes(_configuration["Jwt:Secret"]));

            var claims = new[]
            {
                new Claim(ClaimTypes.NameIdentifier, user.Id),
                new Claim(ClaimTypes.Name, user.UserName),
                new Claim(JwtRegisteredClaimNames.Jti, Guid.NewGuid().ToString())
            };

            var token = new JwtSecurityToken(
                issuer: _configuration["Jwt:Issuer"],
                audience: _configuration["Jwt:Audience"],
                claims: claims,
                expires: DateTime.UtcNow.AddHours(1),
                signingCredentials: new SigningCredentials(key, SecurityAlgorithms.HmacSha256)
            );

            return new JwtSecurityTokenHandler().WriteToken(token);
        }
    }

    public class ApplicationUser : IdentityUser
    {
        public bool RequiresPasswordChange { get; set; } = true;
    }
}
```

**Key Security Controls**:
- **No hardcoded credentials**: All secrets stored in configuration/secrets manager and loaded at runtime
- **ASP.NET Core Identity**: Uses proper password hashing (PBKDF2 by default) and account management
- **First-login password change**: Forces users to set their own password on first login
- **Account lockout**: Prevents brute force attacks by locking accounts after failed attempts

This is a common challenge. The secure approach is to use a setup wizard pattern that requires credentials to be set during first run, combined with proper secrets management. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```csharp
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Configuration;
using System.Security.Cryptography;

namespace AdminPanel.Setup
{
    public interface ISetupService
    {
        Task<bool> IsSetupComplete();
        Task<SetupResult> InitializeAdmin(InitialSetupRequest request);
    }

    public class SecureSetupService : ISetupService
    {
        private readonly ApplicationDbContext _context;
        private readonly UserManager<ApplicationUser> _userManager;
        private readonly RoleManager<IdentityRole> _roleManager;
        private readonly IConfiguration _configuration;
        private readonly ILogger<SecureSetupService> _logger;

        public SecureSetupService(
            ApplicationDbContext context,
            UserManager<ApplicationUser> userManager,
            RoleManager<IdentityRole> roleManager,
            IConfiguration configuration,
            ILogger<SecureSetupService> logger)
        {
            _context = context;
            _userManager = userManager;
            _roleManager = roleManager;
            _configuration = configuration;
            _logger = logger;
        }

        public async Task<bool> IsSetupComplete()
        {
            return await _context.SetupStatus
                .AnyAsync(s => s.IsComplete && s.SetupType == "InitialAdmin");
        }

        public async Task<SetupResult> InitializeAdmin(InitialSetupRequest request)
        {
            // CRITICAL: Only allow setup once
            if (await IsSetupComplete())
            {
                _logger.LogWarning("Attempted setup when already complete from IP: {IP}", 
                    request.RequestingIp);
                return SetupResult.AlreadyComplete();
            }

            // Validate setup token (one-time token generated during deployment)
            if (!await ValidateSetupToken(request.SetupToken))
            {
                _logger.LogWarning("Invalid setup token attempt from IP: {IP}", 
                    request.RequestingIp);
                return SetupResult.InvalidToken();
            }

            // Enforce strong password requirements
            var passwordValidation = await ValidatePasswordStrength(request.Password);
            if (!passwordValidation.IsValid)
            {
                return SetupResult.WeakPassword(passwordValidation.Errors);
            }

            // Ensure admin role exists
            if (!await _roleManager.RoleExistsAsync("Administrator"))
            {
                await _roleManager.CreateAsync(new IdentityRole("Administrator"));
            }

            // Create the admin user with secure settings
            var adminUser = new ApplicationUser
            {
                UserName = request.Username,
                Email = request.Email,
                EmailConfirmed = true,
                RequiresPasswordChange = false, // They just set it
                CreatedAt = DateTime.UtcNow,
                CreatedBy = "InitialSetup",
                TwoFactorEnabled = false, // Prompt to enable after login
                SecurityStamp = Guid.NewGuid().ToString()
            };

            var createResult = await _userManager.CreateAsync(adminUser, request.Password);

            if (!createResult.Succeeded)
            {
                _logger.LogError("Failed to create admin user: {Errors}", 
                    string.Join(", ", createResult.Errors.Select(e => e.Description)));
                return SetupResult.Failed(createResult.Errors);
            }

            await _userManager.AddToRoleAsync(adminUser, "Administrator");

            // Mark setup as complete (prevents replay)
            _context.SetupStatus.Add(new SetupStatus
            {
                SetupType = "InitialAdmin",
                IsComplete = true,
                CompletedAt = DateTime.UtcNow,
                CompletedBy = request.RequestingIp
            });

            // Invalidate the setup token
            await InvalidateSetupToken(request.SetupToken);

            await _context.SaveChangesAsync();

            _logger.LogInformation(
                "Initial admin setup completed. User: {Username}, IP: {IP}",
                request.Username, request.RequestingIp);

            return SetupResult.Success();
        }

        private async Task<bool> ValidateSetupToken(string token)
        {
            // Token generated during deployment and stored securely
            var storedTokenHash = _configuration["Setup:TokenHash"];

            if (string.IsNullOrEmpty(storedTokenHash))
            {
                _logger.LogError("Setup token not configured in environment");
                return false;
            }

            // Constant-time comparison to prevent timing attacks
            var providedHash = ComputeHash(token);
            return CryptographicOperations.FixedTimeEquals(
                Convert.FromBase64String(storedTokenHash),
                Convert.FromBase64String(providedHash));
        }

        private async Task InvalidateSetupToken(string token)
        {
            // In production, remove from secrets manager or mark as used
            _context.UsedSetupTokens.Add(new UsedSetupToken
            {
                TokenHash = ComputeHash(token),
                UsedAt = DateTime.UtcNow
            });
        }

        private async Task<PasswordValidationResult> ValidatePasswordStrength(string password)
        {
            var errors = new List<string>();

            if (password.Length < 14)
                errors.Add("Password must be at least 14 characters");

            if (!password.Any(char.IsUpper))
                errors.Add("Password must contain uppercase letters");

            if (!password.Any(char.IsLower))
                errors.Add("Password must contain lowercase letters");

            if (!password.Any(char.IsDigit))
                errors.Add("Password must contain numbers");

            if (!password.Any(c => !char.IsLetterOrDigit(c)))
                errors.Add("Password must contain special characters");

            // Check against common password list
            if (await IsCommonPassword(password))
                errors.Add("Password is too common");

            return new PasswordValidationResult
            {
                IsValid = !errors.Any(),
                Errors = errors
            };
        }

        private async Task<bool> IsCommonPassword(string password)
        {
            // Check against top 100k passwords database
            var normalizedPassword = password.ToLowerInvariant();
            return await _context.CommonPasswords
                .AnyAsync(p => p.PasswordHash == ComputeHash(normalizedPassword));
        }

        private string ComputeHash(string input)
        {
            using var sha256 = SHA256.Create();
            var bytes = sha256.ComputeHash(System.Text.Encoding.UTF8.GetBytes(input));
            return Convert.ToBase64String(bytes);
        }
    }

    // Setup controller with strict access controls
    [ApiController]
    [Route("api/setup")]
    public class SetupController : ControllerBase
    {
        private readonly ISetupService _setupService;
        private readonly ILogger<SetupController> _logger;

        public SetupController(ISetupService setupService, ILogger<SetupController> logger)
        {
            _setupService = setupService;
            _logger = logger;
        }

        [HttpGet("status")]
        public async Task<IActionResult> GetSetupStatus()
        {
            var isComplete = await _setupService.IsSetupComplete();
            return Ok(new { SetupRequired = !isComplete });
        }

        [HttpPost("initialize")]
        [ServiceFilter(typeof(SetupRateLimitAttribute))] // Max 5 attempts per hour
        public async Task<IActionResult> Initialize([FromBody] InitialSetupRequest request)
        {
            request.RequestingIp = HttpContext.Connection.RemoteIpAddress?.ToString();

            var result = await _setupService.InitializeAdmin(request);

            if (result.Status == SetupResultStatus.Success)
            {
                return Ok(new { Message = "Admin account created successfully" });
            }

            return BadRequest(new { Errors = result.Errors });
        }
    }

    // Startup configuration for secure setup
    public static class SetupExtensions
    {
        public static IServiceCollection AddSecureSetup(this IServiceCollection services)
        {
            services.AddScoped<ISetupService, SecureSetupService>();
            return services;
        }

        public static async Task EnsureSetupTokenGenerated(this IHost host)
        {
            // Generate one-time setup token during first deployment
            using var scope = host.Services.CreateScope();
            var config = scope.ServiceProvider.GetRequiredService<IConfiguration>();

            if (string.IsNullOrEmpty(config["Setup:TokenHash"]))
            {
                var token = GenerateSecureToken();
                Console.WriteLine("===========================================");
                Console.WriteLine("INITIAL SETUP TOKEN (save securely, shown once):");
                Console.WriteLine(token);
                Console.WriteLine("===========================================");

                // In production, store hash in Azure Key Vault / AWS Secrets Manager
                Environment.SetEnvironmentVariable("Setup__TokenHash", ComputeHash(token));
            }
        }

        private static string GenerateSecureToken()
        {
            var bytes = new byte[32];
            RandomNumberGenerator.Fill(bytes);
            return Convert.ToBase64String(bytes);
        }

        private static string ComputeHash(string input)
        {
            using var sha256 = SHA256.Create();
            var bytes = sha256.ComputeHash(System.Text.Encoding.UTF8.GetBytes(input));
            return Convert.ToBase64String(bytes);
        }
    }
}
