For microservice architectures, you need a proper secrets management solution with automatic rotation, auditing, and short-lived credentials. Here's a production-ready approach using HashiCorp Vault or AWS Secrets Manager.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { SecretsManagerClient, GetSecretValueCommand } = require('@aws-sdk/client-secrets-manager');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const winston = require('winston');

const app = express();
app.use(express.json());

// Production-grade logger with audit trail
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'auth-service' },
  transports: [
    new winston.transports.File({ filename: 'audit.log' }),
    new winston.transports.Console()
  ]
});

// Secrets Manager client
const secretsClient = new SecretsManagerClient({ 
  region: process.env.AWS_REGION || 'us-east-1'
});

// In-memory cache for secrets with TTL
class SecretsCache {
  constructor(ttlMs = 300000) { // 5 minute default TTL
    this.cache = new Map();
    this.ttl = ttlMs;
  }

  get(key) {
    const item = this.cache.get(key);
    if (!item) return null;
    if (Date.now() > item.expiry) {
      this.cache.delete(key);
      return null;
    }
    return item.value;
  }

  set(key, value) {
    this.cache.set(key, {
      value,
      expiry: Date.now() + this.ttl
    });
  }
}

const secretsCache = new SecretsCache();

// Fetch secrets from AWS Secrets Manager with caching
async function getSecret(secretName) {
  // Check cache first
  const cached = secretsCache.get(secretName);
  if (cached) return cached;

  try {
    const command = new GetSecretValueCommand({ SecretId: secretName });
    const response = await secretsClient.send(command);
    const secret = JSON.parse(response.SecretString);

    secretsCache.set(secretName, secret);
    logger.info('Secret fetched from Secrets Manager', { secretName, cached: false });

    return secret;
  } catch (error) {
    logger.error('Failed to fetch secret', { secretName, error: error.message });
    throw new Error('Secret retrieval failed');
  }
}

// Service-to-service JWT authentication middleware
const serviceAuthMiddleware = async (req, res, next) => {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    logger.warn('Missing or invalid authorization header', {
      ip: req.ip,
      path: req.path
    });
    return res.status(401).json({ error: 'Authorization required' });
  }

  const token = authHeader.substring(7);

  try {
    // Get JWT signing key from secrets manager
    const secrets = await getSecret(process.env.SERVICE_SECRETS_NAME);

    // Verify JWT with short expiration
    const decoded = jwt.verify(token, secrets.jwtSigningKey, {
      algorithms: ['HS256'],
      maxAge: '5m', // Tokens valid for only 5 minutes
      issuer: 'auth-service',
      audience: process.env.SERVICE_NAME
    });

    // Verify service is in allowed list
    const allowedServices = secrets.allowedServices || [];
    if (!allowedServices.includes(decoded.service)) {
      logger.warn('Unauthorized service attempted access', {
        service: decoded.service,
        ip: req.ip
      });
      return res.status(403).json({ error: 'Service not authorized' });
    }

    req.serviceIdentity = decoded;
    logger.info('Service authenticated', {
      service: decoded.service,
      requestId: decoded.requestId
    });

    next();
  } catch (error) {
    if (error.name === 'TokenExpiredError') {
      logger.warn('Expired service token', { ip: req.ip });
      return res.status(401).json({ error: 'Token expired' });
    }
    logger.error('Service authentication failed', { error: error.message });
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// Generate short-lived service tokens
app.post('/api/internal/token', async (req, res) => {
  const { serviceId, serviceSecret } = req.body;

  try {
    const secrets = await getSecret(process.env.SERVICE_SECRETS_NAME);

    // Verify service credentials (stored hashed in Secrets Manager)
    const serviceCredentials = secrets.serviceCredentials[serviceId];
    if (!serviceCredentials) {
      logger.warn('Unknown service requested token', { serviceId });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Constant-time comparison of service secret hash
    const providedHash = crypto
      .createHash('sha256')
      .update(serviceSecret)
      .digest('hex');

    const isValid = crypto.timingSafeEqual(
      Buffer.from(providedHash),
      Buffer.from(serviceCredentials.secretHash)
    );

    if (!isValid) {
      logger.warn('Invalid service secret', { serviceId, ip: req.ip });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Generate short-lived JWT
    const token = jwt.sign(
      {
        service: serviceId,
        permissions: serviceCredentials.permissions,
        requestId: crypto.randomUUID()
      },
      secrets.jwtSigningKey,
      {
        algorithm: 'HS256',
        expiresIn: '5m',
        issuer: 'auth-service',
        audience: serviceCredentials.allowedAudiences
      }
    );

    logger.info('Service token issued', {
      serviceId,
      expiresIn: '5m'
    });

    res.json({ token, expiresIn: 300 });
  } catch (error) {
    logger.error('Token generation failed', { error: error.message });
    res.status(500).json({ error: 'Token generation failed' });
  }
});

// Protected internal endpoint
app.get('/api/internal/data', serviceAuthMiddleware, (req, res) => {
  logger.info('Internal data accessed', {
    service: req.serviceIdentity.service,
    requestId: req.serviceIdentity.requestId
  });

  res.json({ data: 'internal service data' });
});

// Health check (no auth required)
app.get('/health', (req, res) => {
  res.json({ status: 'healthy' });
});

app.listen(3000, () => {
  logger.info('Auth service started', { port: 3000 });
});
```

